const INTENTS = ['booking_request', 'interested', 'unsubscribe', 'other'];
const keyword = (j) => {
  if (j.__booked) return { intent: 'booking_request', confidence: 0.9 };
  if (j.__stop || j.__unsubscribe) return { intent: 'unsubscribe', confidence: 0.95 };
  const t = (j.__text || '').toString();
  if (/\b(book|appointment|schedule|call|meet|demo|available|availability|time)\b/i.test(t)) return { intent: 'booking_request', confidence: 0.5 };
  if (/\b(yes|interested|sure|sounds good|tell me more|how much|pricing|price|quote)\b/i.test(t)) return { intent: 'interested', confidence: 0.5 };
  if (/\b(no|not interested|stop|remove|unsubscribe)\b/i.test(t)) return { intent: 'unsubscribe', confidence: 0.55 };
  return { intent: 'other', confidence: 0.4 };
};
const ctx = $('Prep Classify').all();
