  if (parsed && status >= 200 && status < 300) {
    const content = parsed.choices && parsed.choices[0] && parsed.choices[0].message && parsed.choices[0].message.content;
    if (typeof content === 'string') {
      // Extract the JSON object by first-brace/last-brace (fence-tolerant, no backticks).
      const a = content.indexOf('{'); const b = content.lastIndexOf('}');
      if (a !== -1 && b > a) { try { v = JSON.parse(content.slice(a, b + 1)); } catch (e) { v = null; } }
    } else if (content && typeof content === 'object') { v = content; }
  }
  let intent, confidence, src;
  if (v && INTENTS.includes(v.intent)) {
    intent = v.intent;
